          "content": "import { Client } from '@temporalio/client';\nimport { transfer, approveSignal } from '../workflow';\nimport type { TransferRequest } from '../models';\n\nconst randomSuffix = () =>\n  Array.from({ length: 6 }, () => 'abcdefghijklmnopqrstuvwxyz'[Math.floor(Math.random() * 26)]).join('');\n\nasync function main() {\n  const client = new Client();\n\n  const request: TransferRequest = {\n    fromAccount: 'account-123',\n    toAccount: 'account-456',\n    amount: 100.0,\n    transferId: 'transfer-1',\n  };\n\n  const handle = await client.workflow.start(transfer, {\n    taskQueue: 'money-transfer-task-queue',\n    workflowId: `money-transfer-workflow-${randomSuffix()}`,\n    args: [request],\n    // TODO: Add searchAttributes to set AccountId\n    // searchAttributes: {\n    //   AccountId: [request.fromAccount],\n    // },\n  });\n\n  await new Promise((resolve) => setTimeout(resolve, 1000));\n  await handle.signal(approveSignal, true);\n\n  const result = await handle.result();\n  console.log(result);\n}\n\nmain().catch((err) => {\n  console.error(err);\n  process.exit(1);\n});\n",
          "solution": "import { Client } from '@temporalio/client';\nimport { transfer, approveSignal } from '../workflow';\nimport type { TransferRequest } from '../models';\n\nconst randomSuffix = () =>\n  Array.from({ length: 6 }, () => 'abcdefghijklmnopqrstuvwxyz'[Math.floor(Math.random() * 26)]).join('');\n\nasync function main() {\n  const client = new Client();\n\n  const request: TransferRequest = {\n    fromAccount: 'account-123',\n    toAccount: 'account-456',\n    amount: 100.0,\n    transferId: 'transfer-1',\n  };\n\n  const handle = await client.workflow.start(transfer, {\n    taskQueue: 'money-transfer-task-queue',\n    workflowId: `money-transfer-workflow-${randomSuffix()}`,\n    args: [request],\n    searchAttributes: {\n      AccountId: [request.fromAccount],\n    },\n  });\n\n  await new Promise((resolve) => setTimeout(resolve, 1000));\n  await handle.signal(approveSignal, true);\n\n  const result = await handle.result();\n  console.log(result);\n}\n\nmain().catch((err) => {\n  console.error(err);\n  process.exit(1);\n});\n"
